import { useState, useEffect } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, Save, Sparkles, Terminal, Box, Database } from 'lucide-react';
import API from '../../api/axios';
import BorderGlow from '../../components/ui/BorderGlow';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import toast from 'react-hot-toast';
import StudioDropdown from '../../components/ui/StudioDropdown';

export default function EditProduct() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [genLoading, setGenLoading] = useState(false);
  const [form, setForm] = useState({ name: '', description: '', price: '', stock_qty: '', brand: '', category_id: '', is_active: true, image_url: '' });
  const [categories, setCategories] = useState([]);

  const catOptions = categories.map(c => ({ value: c.category_id, label: c.name }));

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [catRes, prodRes] = await Promise.all([
          API.get('/categories'),
          API.get(`/vendor/products/${id}`)
        ]);
        setCategories(catRes.data.categories || []);
        const p = prodRes.data.product;
        if (!p) throw new Error('Product not found');
        setForm({
          name: p.name,
          description: p.description,
          price: p.price,
          stock_qty: p.stock_qty,
          brand: p.brand,
          category_id: p.category_id,
          is_active: p.is_active,
          image_url: p.image_url || ''
        });
      } catch (err) {
        toast.error('Failed to load product data');
        navigate('/vendor/products');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [id, navigate]);

  const update = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handleGenerate = async () => {
    if (!form.name || !form.category_id) return toast.error('Enter name & category first');
    setGenLoading(true);
    try {
      const res = await API.post('/products/generate-description', {
        name: form.name, category_id: parseInt(form.category_id), price: parseFloat(form.price || 0), brand: form.brand,
      });
      update('description', res.data.description);
      toast.success('Description regenerated by AI!');
    } catch { toast.error('AI generation failed.'); }
    finally { setGenLoading(false); }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await API.put(`/vendor/products/${id}`, { 
        ...form, 
        price: parseFloat(form.price), 
        stock_qty: parseInt(form.stock_qty || 0), 
        category_id: parseInt(form.category_id) 
      });
      toast.success('Product updated successfully');
      navigate('/vendor/products');
    } catch (err) { toast.error(err.response?.data?.error || 'Update failed'); }
    finally { setSubmitting(false); }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center"><LoadingSpinner size="lg" text="Retrieving Hardware Specs..." /></div>;

  return (
    <div className="section-padding py-16 sm:py-24 max-w-4xl mx-auto">
      <Link to="/vendor/products" className="inline-flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 hover:text-primary-500 mb-12 transition-colors group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" /> Back to Repository
      </Link>
      
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
        <header className="mb-12">
          <span className="text-[10px] font-black uppercase tracking-[0.4em] text-primary-500 mb-4 block">Hardware Reconfiguration</span>
          <h1 className="text-5xl sm:text-6xl font-black text-surface-950 dark:text-white mb-4 tracking-tighter">Edit <span className="text-surface-400">Component.</span></h1>
          <p className="text-surface-500 font-medium text-lg">Modify existing hardware parameters in the global marketplace catalog.</p>
        </header>

        <form onSubmit={handleSubmit} className="space-y-12">
          <BorderGlow className="w-full" borderRadius={48} glowRadius={10} animated={true}>
            <div className="p-10 sm:p-12 relative overflow-hidden w-full">
              <div className="flex items-center gap-4 mb-10">
                <div className="w-10 h-10 rounded-xl bg-primary-500/10 flex items-center justify-center text-primary-500">
                  <Terminal className="w-5 h-5" />
                </div>
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-surface-950 dark:text-white">General Parameters</h3>
              </div>

              <div className="space-y-8">
                <div className="group w-full">
                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 mb-3">Canonical Name *</label>
                  <input type="text" value={form.name} onChange={(e) => update('name', e.target.value)} className="input-field !py-5 !px-8 !rounded-2xl w-full" required />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 w-full">
                  <div className="group w-full">
                    <StudioDropdown 
                      label="Product Category"
                      value={form.category_id}
                      options={catOptions}
                      onChange={(val) => setForm({ ...form, category_id: val })}
                    />
                  </div>
                  <div className="group w-full">
                    <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 mb-3">Brand Identity</label>
                    <input type="text" value={form.brand} onChange={(e) => update('brand', e.target.value)} className="input-field !py-5 !px-8 !rounded-2xl w-full" />
                  </div>
                </div>
              </div>
            </div>
          </BorderGlow>

          {/* Visual Assets */}
          <BorderGlow className="w-full" borderRadius={48} glowRadius={10} animated={true}>
            <div className="p-10 sm:p-12 relative overflow-hidden w-full">
              <div className="flex items-center gap-4 mb-10">
                <div className="w-10 h-10 rounded-xl bg-indigo-500/10 flex items-center justify-center text-indigo-500">
                  <Box className="w-5 h-5" />
                </div>
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-surface-950 dark:text-white">Visual Assets</h3>
              </div>
              
              <div className="group w-full">
                <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 mb-3 group-focus-within:text-indigo-500 transition-colors">Product Image URL</label>
                <input type="url" value={form.image_url} onChange={(e) => update('image_url', e.target.value)} 
                  placeholder="https://images.unsplash.com/photo-..." 
                  className="input-field !py-5 !px-8 !rounded-2xl border-surface-100 dark:border-white/5 bg-surface-50/50 dark:bg-white/[0.02] w-full" />
                <p className="mt-4 text-[10px] text-surface-400 font-medium">Provide a direct link to a high-resolution JPEG/PNG asset.</p>
              </div>
            </div>
          </BorderGlow>

          <BorderGlow className="w-full" borderRadius={48} glowRadius={10} animated={true}>
            <div className="p-10 sm:p-12 w-full">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 w-full">
                <div className="group w-full">
                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 mb-3">Value (PKR) *</label>
                  <input type="number" value={form.price} onChange={(e) => update('price', e.target.value)} className="input-field !py-5 !px-8 !rounded-2xl w-full" required />
                </div>
                <div className="group w-full">
                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-surface-400 mb-3">Stock Level</label>
                  <input type="number" value={form.stock_qty} onChange={(e) => update('stock_qty', e.target.value)} className="input-field !py-5 !px-8 !rounded-2xl w-full" />
                </div>
              </div>
              <div className="mt-8 flex items-center gap-3">
                <input type="checkbox" id="is_active" checked={form.is_active} onChange={(e) => update('is_active', e.target.checked)} className="w-5 h-5 rounded-md border-surface-200 dark:border-white/10" />
                <label htmlFor="is_active" className="text-xs font-black uppercase tracking-widest text-surface-600 dark:text-surface-300">Active Deployment Status</label>
              </div>
            </div>
          </BorderGlow>

          <BorderGlow className="w-full" borderRadius={48} glowRadius={10} animated={true}>
            <div className="p-10 sm:p-12 w-full flex flex-col">
              <div className="flex justify-between items-center mb-10 w-full">
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-surface-950 dark:text-white">Technical Specification</h3>
                <button type="button" onClick={handleGenerate} disabled={genLoading} className="text-[10px] font-black uppercase tracking-[0.2em] text-primary-500 flex items-center gap-3">
                  {genLoading ? <div className="w-4 h-4 border-2 border-primary-500 border-t-transparent rounded-full animate-spin" /> : <Sparkles className="w-4 h-4" />}
                  Recalibrate via AI
                </button>
              </div>
              <textarea value={form.description} onChange={(e) => update('description', e.target.value)} className="input-field !py-8 !px-8 !rounded-[32px] min-h-[200px] w-full resize-none" />
            </div>
          </BorderGlow>

          <button type="submit" disabled={submitting} className="btn-primary w-full !py-6 !rounded-[24px] flex items-center justify-center gap-4">
            {submitting ? <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin" /> : <> <Save className="w-5 h-5" /> <span className="text-sm font-black uppercase tracking-[0.3em]">Commit Changes</span> </>}
          </button>
        </form>
      </motion.div>
    </div>
  );
}
